import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)

changes = []
unchanged = []
for key in sorted(set(b.keys()) | set(a.keys())):
    proj, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv != av:
        changes.append((proj, pkg, bv or '(none)', av or '(none)'))
    else:
        unchanged.append((proj, pkg, av))

print('=== CHANGES ===')
for c in changes:
    print(f'  {c[0]:20s} {c[1]:40s} {c[2]:10s} -> {c[3]}')
print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]:20s} {u[1]:40s} {u[2]}')
